"use client";

import React, { useEffect } from "react";

import "./globals.css";
import { Toaster } from "react-hot-toast";
import { Navbar } from "@/components/layout/Navbar";
import { Footer } from "@/components/layout/Footer";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";

import { Inter } from "next/font/google";

const inter = Inter({
  subsets: ["latin"],
  variable: "--font-inter",
});

const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      refetchOnWindowFocus: false,
    },
  },
});

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  // A small trick to handle hydration mismatch with next themes if needed, but we'll stick to basic.
  return (
    <html lang="en">
      <head>
        <title>ShopMart | Premium E-Commerce</title>
        <meta name="description" content="Your ultimate graduation project e-commerce platform." />
      </head>
      <body
        suppressHydrationWarning
        className={`${inter.variable} font-sans antialiased bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-slate-50 flex flex-col min-h-screen selection:bg-orange-500/30 selection:text-orange-900 dark:selection:text-orange-100`}
      >
        <QueryClientProvider client={queryClient}>
          <Toaster 
            position="top-center" 
            reverseOrder={false} 
            toastOptions={{
              style: {
                borderRadius: '10px',
                background: '#333',
                color: '#fff',
              },
            }}
          />
          <Navbar />
          <main className="flex-1 flex flex-col">
            {children}
          </main>
          <Footer />
        </QueryClientProvider>
      </body>
    </html>
  );
}
