import { axiosInstance } from "@/lib/axios";
import { CartResponse } from "@/types/cart";
import { Product } from "@/types/product";

export const CartService = {
  getCart: async () => {
    const { data } = await axiosInstance.get<CartResponse>("/api/v1/cart");
    return data;
  },

  addToCart: async (productId: string) => {
    const { data } = await axiosInstance.post<CartResponse>("/api/v1/cart", { productId });
    return data;
  },

  updateCartQuantity: async (productId: string, count: number) => {
    const { data } = await axiosInstance.put<CartResponse>(`/api/v1/cart/${productId}`, { count });
    return data;
  },

  removeFromCart: async (productId: string) => {
    const { data } = await axiosInstance.delete<CartResponse>(`/api/v1/cart/${productId}`);
    return data;
  },

  clearCart: async () => {
    const { data } = await axiosInstance.delete("/api/v1/cart");
    return data;
  }
};

export interface WishlistResponse {
  status: string;
  count: number;
  data: Product[];
}

export const WishlistService = {
  getWishlist: async () => {
    const { data } = await axiosInstance.get<WishlistResponse>("/api/v1/wishlist");
    return data;
  },

  addToWishlist: async (productId: string) => {
    const { data } = await axiosInstance.post("/api/v1/wishlist", { productId });
    return data;
  },

  removeFromWishlist: async (productId: string) => {
    const { data } = await axiosInstance.delete(`/api/v1/wishlist/${productId}`);
    return data;
  }
};
